import { describe, expect, test } from "bun:test";
import { code, flow, ref, s } from "./index";

describe("code() helper", () => {
  test("serializes typed function to javascript_code step", () => {
    const step = code<{ date: string }>((ctx) => ({
      date: ctx.input.date,
      rooms: ctx.nodes.rooms,
    }));

    expect(step.call).toBe("javascript_code");
    expect(typeof step.config.code).toBe("string");
    expect(String(step.config.code)).toContain("async function main({ input, automation, nodes");
    expect(String(step.config.code)).toContain("ctx.input.date");
    expect(step.config.input_data).toEqual({});
    expect(step.config.timeout_ms).toBe(5000);
    expect(step.config.runtime).toBe("vm");
  });

  test("rejects flow builder helper references inside code body", () => {
    expect(() =>
      code(() => ref.input("date") as unknown as Record<string, unknown>),
    ).toThrow(/flow builder helpers/);
  });

  test("allows runtime helpers through ctx", () => {
    const step = code(async (ctx) => {
      const rows = await ctx.db!.query("SELECT 1", []);
      const response = await ctx.http!.get("https://example.com");
      return { rows, response };
    });

    expect(step.call).toBe("javascript_code");
    expect(String(step.config.code)).toContain("ctx.db");
    expect(String(step.config.code)).toContain("ctx.http");
  });

  test("FlowBuilder.code infers input shape from .input()", () => {
    const builder = flow("typed-code")
      .http({ method: "GET", auth: "public" })
      .input({ date: s.date(), limit: s.optional(s.number()) });

    const definition = builder
      .step("compute", builder.code((ctx) => ({ date: ctx.input.date })))
      .return({ date: ref.literal("2026-06-05") });

    const computeStep = definition.steps.find((step) => step.id === "compute");
    expect(computeStep?.call).toBe("javascript_code");
    expect(String(computeStep?.config.code)).toContain("input.date");
  });

  test("supports custom timeout and env", () => {
    const step = code(
      (ctx) => ({ region: ctx.env.REGION }),
      { timeoutMs: 8000, env: { REGION: "EU" } },
    );
    expect(step.config.timeout_ms).toBe(8000);
    expect(step.config.env_vars).toEqual([{ key: "REGION", value: "EU" }]);
  });
});
